insert into nodes (id, campaign_id, type_id, title, fields) values
  ('30000000-0000-0000-0000-000000000001', '00000000-0000-0000-0000-000000000001', '10000000-0000-0000-0000-000000000001',
   'Альд Манкод', '{"player":"Алек","description":"Отмечен Алым Потоком, знаком пепельных глаз и волос. Служит Великой Реке в церкви Багряного Конклава. Жрец Заката.","tags":["3-курс","жрец"]}'),
  ('30000000-0000-0000-0000-000000000002', '00000000-0000-0000-0000-000000000001', '10000000-0000-0000-0000-000000000001',
   'Дрипли Вирион', '{"player":"Егор","description":"Клуб искателей приключений, 2 года от роду, слизь, жертва эксперимента, один из переживших Плач. Изобретатель-алхимик.","tags":["3-курс","слизь","алхимик"]}'),
  ('30000000-0000-0000-0000-000000000003', '00000000-0000-0000-0000-000000000001', '10000000-0000-0000-0000-000000000001',
   'Маркус Хоппер', '{"player":"Стасян","description":"Сборная академии по борьбе, 50% шанс на встречу с фанатом в 100 милях от академии, автор песни «шняга шняжная».","tags":["3-курс","монах","борьба"]}'),
  ('30000000-0000-0000-0000-000000000004', '00000000-0000-0000-0000-000000000001', '10000000-0000-0000-0000-000000000001',
   'Британия Мерц', '{"player":"Андрей","description":"Эмпатка, капитан чирлидеров, дочь богатого пивовара. Умершая от Плача мать, увлекается актёрской игрой, военной историей.","tags":["3-курс","эмпат","чирлидер","бард"]}'),
  ('30000000-0000-0000-0000-000000000005', '00000000-0000-0000-0000-000000000001', '10000000-0000-0000-0000-000000000001',
   'Янка Мавики', '{"player":"Катя","description":"16 лет, цимбалы, Клуб искателей приключений, моментальная смена настроений. Дикая магия.","tags":["3-курс","дикая-магия"]}');

