  ('30000000-0000-0000-0000-000000000011', '00000000-0000-0000-0000-000000000001', '10000000-0000-0000-0000-000000000002',
   'Тайвен', '{"description":"Семнадцать лет, выпускница Академии, ассистент преподавателя немагического боя. Наглая, боевой маг, выглядит как Корра из Аватара.","status":"Выпускница","tags":["боевой-маг"]}'),
  ('30000000-0000-0000-0000-000000000012', '00000000-0000-0000-0000-000000000001', '10000000-0000-0000-0000-000000000002',
