  ('30000000-0000-0000-0000-000000000015', '00000000-0000-0000-0000-000000000001', '10000000-0000-0000-0000-000000000002',
   'Хаслуш Экзетери', '{"description":"Детектив полицейского управления Сиории, маг-прорицатель. Учит прорицанию, использует Область Истины.","status":"Детектив","tags":["детектив","прорицатель"]}'),
  ('30000000-0000-0000-0000-000000000016', '00000000-0000-0000-0000-000000000001', '10000000-0000-0000-0000-000000000002',
   'Имайя Курошка', '{"description":"Домовладелица и подруга Ильзы. Одинока, бесплодна, заботится о постояльцах. Очень говорлива.","status":"Горожанка","tags":["горожанка"]}'),
  ('30000000-0000-0000-0000-000000000017', '00000000-0000-0000-0000-000000000001', '10000000-0000-0000-0000-000000000002',
   'Бенисек', '{"description":"Толстенький ленивый любитель сплетен, сын богатых торговцев. Незаменим для сбора информации, может мгновенно разнести любой слух.","status":"3 курс","tags":["3-курс","сплетник"]}'),
  ('30000000-0000-0000-0000-000000000018', '00000000-0000-0000-0000-000000000001', '10000000-0000-0000-0000-000000000002',
   'Акоджа Строуз', '{"description":"Староста группы Зориана, прилежная ученица, аккуратистка, каштановые волосы, очки.","status":"3 курс","tags":["3-курс","группа-1","староста"]}'),
  ('30000000-0000-0000-0000-000000000019', '00000000-0000-0000-0000-000000000001', '10000000-0000-0000-0000-000000000002',
   'Лайонел Вирион', '{"description":"Эксперт алхимии, преподаватель Академии. Отец/создатель Дрипли. Надеется пробудить душу сына в слизи.","status":"Преподаватель","tags":["преподаватель","алхимия"]}'),
  ('30000000-0000-0000-0000-000000000020', '00000000-0000-0000-0000-000000000001', '10000000-0000-0000-0000-000000000002',
   'Нора Буул', '{"description":"Преподавательница заклинательных формул и высшей математики. Экзальтированная, оранжевые волосы, задаёт невозможно много.","status":"Преподаватель","tags":["преподаватель","формулы"]}');

